sql:
SELECT "attributes"."name", "users"."role"
FROM "attributes"
INNER JOIN "users" ON "attributes"."created_by" = "users"."user_id";

SELECT name, mandatory
FROM attributes
ORDER BY name ASC;

SELECT T1.attribute_id, T2.usage_count
FROM attributes AS T1
JOIN attribute_analytics AS T2 ON T1.attribute_id = T2.attribute_id;

external_knowledge:
- "waves of change" metaphorically refers to modifications in the attribute's history;
- "rich as a thousand-page novel" metaphorically indicates extensive documentation, here meaning more than 15 words;
- The process of calculating the number of words in a string involves counting spaces and adding one.

sql:
SELECT attributes.name
FROM attributes
WHERE attributes.updated_by NOT IN (SELECT DISTINCT user_id FROM attribute_user_map);

SELECT attribute_id, name, mandatory, data_type_id, default_value, length, created_by, created_date, updated_by, updated_date
FROM attributes
WHERE attribute_id = 0;

SELECT map_id, attribute_id, user_id, action
FROM attribute_user_map
WHERE action = 'created';

SELECT mandatory, data_type_id, COUNT(attribute_id) AS count
FROM attributes
GROUP BY mandatory, data_type_id;

SELECT extension_name, version
FROM extensions
WHERE extension_id = 0;

SELECT attributes.name, attributes.data_type_id, data_types.category
FROM attributes
INNER JOIN data_types ON attributes.data_type_id = data_types.data_type_id;

SELECT suggestion
FROM attribute_optimization
WHERE attribute_id = 0 AND optimization_id = 0;

external_knowledge:
- Gardeners: Users in the system;
- Flowers: Attributes that can be updated by users;
- Tended to: The act of updating attributes.

sql:
SELECT COUNT(*) AS total_usage_count
FROM attribute_usage
WHERE attribute_id = 1;

external_knowledge:
- 'Pillars holding up the structure' refers to mandatory attributes;
- 'Essential texts' indicate attributes that are both mandatory and of 'text' data type;
- 'Floating outside the realm of 'ModuleA'' means attributes that are not associated with 'ModuleA'.

sql:
SELECT a.name, a.created_date
FROM attributes AS a
JOIN attribute_documentation AS ad ON a.attribute_id = ad.attribute_id;
